import{_ as o,o as d,c as i,ag as l}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"API 快速索引","description":"","frontmatter":{},"headers":[],"relativePath":"api.md","filePath":"api.md","lastUpdated":1775494190000}'),a={name:"api.md"};function c(r,e,t,p,s,n){return d(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="api-快速索引" tabindex="-1">API 快速索引 <a class="header-anchor" href="#api-快速索引" aria-label="Permalink to &quot;API 快速索引&quot;">​</a></h1><p>这个页面主要作为 API 入口和对象速查表。</p><p>如果目标是接前端、联调 FastAPI 宿主或直接消费 HTTP / SSE / WebSocket 协议，请先看 <a href="/server-api">服务端 API 手册</a>。</p><p>如果目标是安装和运行宿主应用，先看 <a href="/install">安装与发布</a>；如果目标是开发 driver，先看 <a href="/sdk">SDK 开发者指南</a>。</p><p>当前 API 说明以 <code>0.2.0</code> 主线为准：</p><ul><li><code>modlink_sdk</code> / <code>modlink_core</code> 已经是纯 Python runtime</li><li><code>0.2.0</code> 不兼容 <code>0.1.x</code> 的 Qt-style driver API</li><li>UI 包当前分为 <code>modlink_ui_qt_widgets</code> 和 <code>modlink_ui_qt_qml</code></li><li>插件管理 CLI 当前由 <code>modlink_plugin_manager</code> 提供</li></ul><h2 id="web-api-入口" tabindex="-1">Web API 入口 <a class="header-anchor" href="#web-api-入口" aria-label="Permalink to &quot;Web API 入口&quot;">​</a></h2><ul><li>前端接入和服务端联调：看 <a href="/server-api">服务端 API 手册</a></li></ul><h2 id="完整-api-参考" tabindex="-1">完整 API 参考 <a class="header-anchor" href="#完整-api-参考" aria-label="Permalink to &quot;完整 API 参考&quot;">​</a></h2><p>从源码 docstring 自动生成的 API 文档入口如下：</p><ul><li><a href="/pdoc/index.html" target="_self">打开 pdoc 总览</a></li></ul><p>当前主要包的入口如下：</p><ul><li><a href="/pdoc/modlink_sdk.html" target="_self">modlink_sdk</a></li><li><a href="/pdoc/modlink_core.html" target="_self">modlink_core</a></li><li><a href="/pdoc/modlink_plugin_manager.html" target="_self">modlink_plugin_manager</a></li><li><a href="/pdoc/modlink_ui_qt_widgets.html" target="_self">modlink_ui_qt_widgets</a></li><li><a href="/pdoc/modlink_ui_qt_qml.html" target="_self">modlink_ui_qt_qml</a></li><li><a href="/pdoc/modlink_studio.html" target="_self">modlink_studio</a></li><li><a href="/pdoc/modlink_studio_qml.html" target="_self">modlink_studio_qml</a></li></ul><h2 id="先建立一条最小接入链路" tabindex="-1">先建立一条最小接入链路 <a class="header-anchor" href="#先建立一条最小接入链路" aria-label="Permalink to &quot;先建立一条最小接入链路&quot;">​</a></h2><p>从 SDK 视角看，一个 driver 的最小工作链路通常是：</p><ol><li>宿主创建一个 <code>Driver</code> 或 <code>LoopDriver</code> 实例</li><li>宿主调用 <code>bind(context)</code>，注入 <code>DriverContext</code></li><li>宿主调用 <code>descriptors()</code>，读取这个 driver 会暴露哪些 <code>StreamDescriptor</code></li><li>宿主调用 <code>search()</code>，拿到一组 <code>SearchResult</code></li><li>宿主把选中的 <code>SearchResult</code> 传回 <code>connect_device()</code></li><li>driver 开始流并提供实时数据后，通过 <code>emit_frame()</code> 发出 <code>FrameEnvelope</code></li><li>每个 <code>FrameEnvelope</code> 都必须能够对应到前面声明过的某个 <code>StreamDescriptor</code></li></ol><p>如果这条链路里有一环没有定义清楚，宿主、录制和 UI 就很难稳定工作。更需要先定清楚的不是“页面长什么样”，而是：</p><ul><li>这个 driver 有哪些 stream</li><li>每个 stream 的 <code>payload_type</code> 是什么</li><li>每次发出的 <code>FrameEnvelope.data</code> shape 应该怎么解释</li></ul><h2 id="最常看的对象" tabindex="-1">最常看的对象 <a class="header-anchor" href="#最常看的对象" aria-label="Permalink to &quot;最常看的对象&quot;">​</a></h2><h3 id="driver" tabindex="-1"><code>Driver</code> <a class="header-anchor" href="#driver" aria-label="Permalink to &quot;`Driver`&quot;">​</a></h3><p><code>Driver</code> 是所有 driver 的根基类，也是最保守、最通用的起点。它定义的是宿主能够理解的统一生命周期，而不是某种具体设备协议。</p><p>最核心的方法包括：</p><ul><li><code>descriptors()</code></li><li><code>search()</code></li><li><code>connect_device()</code> / <code>disconnect_device()</code></li><li><code>start_streaming()</code> / <code>stop_streaming()</code></li><li><code>bind(context)</code></li><li><code>emit_frame()</code></li></ul><p>如果暂时无法判断设备是不是标准轮询模型，默认回到 <code>Driver</code>。它的抽象更直接，也更不容易把设备逻辑硬套进不合适的轮询结构。</p><h3 id="loopdriver" tabindex="-1"><code>LoopDriver</code> <a class="header-anchor" href="#loopdriver" aria-label="Permalink to &quot;`LoopDriver`&quot;">​</a></h3><p><code>LoopDriver</code> 建立在 <code>Driver</code> 之上，适合轮询型设备。它已经帮你封装了：</p><ul><li>基于 runtime 的周期调度</li><li><code>start_streaming()</code> / <code>stop_streaming()</code> 的默认实现</li><li><code>on_loop_started()</code> / <code>on_loop_stopped()</code> 这两个可选钩子</li></ul><p>通常只需要补齐：</p><ul><li><code>descriptors()</code></li><li><code>search()</code></li><li><code>connect_device()</code> / <code>disconnect_device()</code></li><li><code>loop()</code></li></ul><h3 id="searchresult" tabindex="-1"><code>SearchResult</code> <a class="header-anchor" href="#searchresult" aria-label="Permalink to &quot;`SearchResult`&quot;">​</a></h3><p><code>SearchResult</code> 是 <code>search()</code> 返回的候选设备对象。宿主只做两件事：</p><ul><li>用 <code>title</code> / <code>subtitle</code> 展示给用户</li><li>在用户选中后，把整个对象回传给 <code>connect_device()</code></li></ul><p>宿主不会解析 <code>extra</code>。端口号、地址、序列号和传输参数等连接信息都可以放在这里，由 driver 自己消费。</p><h3 id="streamdescriptor" tabindex="-1"><code>StreamDescriptor</code> <a class="header-anchor" href="#streamdescriptor" aria-label="Permalink to &quot;`StreamDescriptor`&quot;">​</a></h3><p><code>StreamDescriptor</code> 描述的是“这个 driver 会发出什么流”，它是静态契约，不是实时数据。</p><p>最关键的字段有：</p><ul><li><code>device_id</code></li><li><code>modality</code></li><li><code>payload_type</code></li><li><code>nominal_sample_rate_hz</code></li><li><code>chunk_size</code></li><li><code>channel_names</code></li><li><code>display_name</code></li><li><code>metadata</code></li></ul><p>其中 <code>payload_type</code> 当前只能从 <code>signal</code>、<code>raster</code>、<code>field</code>、<code>video</code> 中选择；UI 和录制链路会根据它解释 <code>FrameEnvelope.data</code>。</p><h3 id="frameenvelope" tabindex="-1"><code>FrameEnvelope</code> <a class="header-anchor" href="#frameenvelope" aria-label="Permalink to &quot;`FrameEnvelope`&quot;">​</a></h3><p><code>FrameEnvelope</code> 是运行时真正发出的数据块。前面的 <code>StreamDescriptor</code> 负责“声明”，<code>FrameEnvelope</code> 负责“兑现”这个声明。</p><p>每次发帧时，最关键的是：</p><ul><li><code>stream_id</code></li><li><code>timestamp_ns</code></li><li><code>data</code></li><li><code>seq</code></li><li><code>extra</code></li></ul><p>最重要的三条约束是：</p><ol><li><code>stream_id</code> 必须能对应到某个 <code>StreamDescriptor</code></li><li><code>data.shape</code> 必须和该流的约定一致</li><li><code>timestamp_ns</code> 应该有真实时间语义</li></ol><h2 id="继续阅读" tabindex="-1">继续阅读 <a class="header-anchor" href="#继续阅读" aria-label="Permalink to &quot;继续阅读&quot;">​</a></h2><ul><li>想接设备：看 <a href="/sdk">SDK</a></li><li>想理解运行时：看 <a href="/core">Core</a></li><li>想做展示层：看 <a href="/ui">UI</a></li><li>想理解宿主入口：看 <a href="/app">App</a></li></ul>',46)])])}const _=o(a,[["render",c]]);export{m as __pageData,_ as default};
